solution_code:
#include <iostream>
#include <limits>

int main()
{
    int data[10]{};
    int n{};
    std::cin >> n;

    for (int i{ 0 }; i < n; ++i)
    {
        std::cin >> data[i];
    }

    int sum{ 0 };
    int min{ std::numeric_limits<int>::max() };
    int max{ std::numeric_limits<int>::min() };

    for (int i{ 0 }; i < n; ++i)
    {
        sum += data[i];
        if (data[i] < min)
            min = data[i];
        if (data[i] > max)
            max = data[i];
    }

    std::cout << sum << '\n';
    std::cout << min << '\n';
    std::cout << max << '\n';

    return 0;
}

