#include <cstddef>
#include <iostream>

int main()
{
    int arr[8]{};
    const std::size_t length{ sizeof(arr) / sizeof(arr[0]) };

    for (std::size_t i{ 0 }; i < length; ++i)
        std::cin >> arr[i];

    for (std::size_t i{ 0 }; i < length; ++i)
    {
        if (i != 0)
            std::cout << ' ';
        std::cout << arr[length - 1 - i];
    }
    std::cout << '\n';

    int positives{ 0 };
    for (std::size_t i{ 0 }; i < length; ++i)
    {
        if (arr[i] > 0)
            ++positives;
    }

    std::cout << "Positives: " << positives << '\n';

    return 0;
}
